import React, { useState, useEffect } from "react";
import { GetParentSetting, AddChildPermission } from "../../api/api";
import { toast } from "react-toastify";

const permissionFields = {
  email_partner: [{ key: "new_user_registered", label: "Applicant's Registration mail" }],
  email_employee: [{ key: "employee_signup", label: "Welcome Mail" }],
  email_employer: [
    { key: "lmia", label: "Lmia" },
    { key: "visa", label: "Visa" },
    { key: "interview", label: "Interview" },
    { key: "job", label: "Job" },
  ],
  notification_employee: [
    { key: "lmia", label: "Lmia" },
    { key: "visa", label: "Visa" },
    { key: "interview", label: "Interview" },
    { key: "job", label: "Job" },
  ],
  notification_employer: [
    { key: "lmia", label: "Lmia" },
    { key: "visa", label: "Visa" },
    { key: "interview", label: "Interview" },
    { key: "job", label: "Job" },
  ],
};

export default function ParentSetting({ setopenAdminSettings, setApiCall }) {
  const [selectedOption, setSelectedOption] = useState("");
  const [permissions, setPermissions] = useState({});

  useEffect(() => {
    if (!selectedOption) return;
    if (selectedOption === "admin_setting") {
      setopenAdminSettings(true);
      setApiCall(true);
      setPermissions({});
      setSelectedOption("");
      return;
    }
    async function fetchPermissions() {
      try {
        const res = await GetParentSetting(selectedOption);
        if (res.status === 1) {
          setPermissions(JSON.parse(res.data[0]?.permission || "{}"));
        } else {
          setPermissions({});
        }
        setopenAdminSettings(false);
      } catch (err) {
        console.error(err);
        setPermissions({});
        setopenAdminSettings(false);
      }
    }
    fetchPermissions();
  }, [selectedOption, setopenAdminSettings, setApiCall]);

  const togglePermission = async (key) => {
    const updated = { ...permissions, [key]: permissions[key] === 1 ? 0 : 1 };
    try {
      const res = await AddChildPermission({ type: selectedOption, permission: updated });
      if (res.message === "successfully") {
        setPermissions(updated);
        toast[updated[key] === 1 ? "success" : "error"](
          `Permission ${updated[key] === 1 ? "granted" : "denied"} successfully`,
          { position: toast.POSITION.TOP_RIGHT, autoClose: 1000 }
        );
      }
    } catch (err) {
      console.error(err);
    }
  };

  const fields = permissionFields[selectedOption] || [];

  return (
    <div>
      <select className="form-control" value={selectedOption} onChange={(e) => setSelectedOption(e.target.value)}>
        <option value="">Select Type</option>
        <option value="admin_setting">Admin's Settings</option>
        <option value="email_partner">Partner's Email</option>
        <option value="email_employee">Applicant's Email</option>
        <option value="email_employer">Employer's Email</option>
        <option value="notification_employee">Applicant's Notification</option>
        <option value="notification_employer">Employer's Notification</option>
      </select>

      {selectedOption && selectedOption !== "admin_setting" && (
        <>
          <h6 className="text-start mt-4 text-grey text-capitalize">{selectedOption.replaceAll("_", " ")} Preferences</h6>
          <ul className="list-unstyled row">
            {fields.map(({ key, label }) => (
              <li className="mb-3 col-6" key={key}>
                <div className="custom-control custom-switch">
                  <input
                    type="checkbox"
                    className="custom-control-input"
                    id={`customSwitch-${key}`}
                    checked={!!permissions[key]}
                    onChange={() => togglePermission(key)}
                  />
                  <label className="custom-control-label" htmlFor={`customSwitch-${key}`}>
                    {label}
                  </label>
                </div>
              </li>
            ))}
          </ul>
        </>
      )}
    </div>
  );
}
